static mut INITIALIZED: bool = false;

pub static OWNSOME_BANNER: &str = r#"
   ___                      _____
  / _ \__      _____ ___   / ___|  _ __ ___   ___  ___
 | | | \ \ /\ / / __/ __|  \___ \ | '_ ` _ \ / _ \/ __|
 | |_| |\ V  V /\__ \__ \   ___) || | | | | |  __/\__ \
  \___/  \_/\_/ |___/___/  |____/ |_| |_| |_|\___||___/
"#;

pub fn rust_main(hart_id: usize, dtb_addr: usize) -> ! {
    println!("hart id: {}, dtb_addr: {:#x}", hart_id, dtb_addr);
    // SAFETY: Only the first hart will run this code block.
    if unsafe { !INITIALIZED } {
        println!("print init");
        /* Initialize logger */

        println!("hart id: {}, dtb_addr: {:#p}", hart_id, &dtb_addr);
        boot::clear_bss();

        // too much log delay, cut up!
        logger::init();
        disable_log();
        // enable_log();
        // enable_filter(1);

        log::info!("dtb_addr: {:#x}", dtb_addr);

        #[cfg(target_arch = "loongarch64")]
        log::warn!("ARCH: loongarch64");

        #[cfg(target_arch = "riscv64")]
        log::warn!("ARCH: riscv64");

        println!("mem init");
        /* Initialize heap allocator and page table */
        unsafe {
            DTB_ADDR = dtb_addr;

            println!("try to init heap");

            heap::init_heap_allocator();
            log::info!("hart {}: initialized heap allocator", hart_id);
            println!("init_heap_allocator");

            frame::init_frame_allocator();
            log::info!("hart {}: initialized frame allocator", hart_id);
            println!("init_frame_allocator");

            vm::switch_to_kernel_page_table();
            log::info!("hart {}: switched to kernel page table", hart_id);
            println!("switch_to_kernel_page_table");

            fence();
            ptr::write_volatile(&raw mut INITIALIZED, true);
        }
        println!("memory init success");

        println!(
            "kernel physical memory: {:#x} - {:#x}",
            config::mm::KERNEL_START_PHYS,
            config::mm::kernel_end_phys(),
        );
        println!(
            "kernel virtual memory: {:#x} - {:#x}",
            config::mm::KERNEL_START,
            config::mm::kernel_end()
        );
        println!(
            ".text {:#x} - {:#x}",
            config::mm::text_start(),
            config::mm::text_end()
        );
        println!(
            ".rodata {:#x} - {:#x}",
            config::mm::rodata_start(),
            config::mm::rodata_end()
        );
        println!(
            ".data {:#x} - {:#x}",
            config::mm::data_start(),
            config::mm::data_end()
        );
        println!(
            ".bss {:#x} - {:#x}",
            config::mm::bss_start(),
            config::mm::bss_end()
        );
        log::info!("device tree blob {:#x} - {:#x}", DTB_START, DTB_END,);
        log::info!("device tree blob PA start: {:#x}", dtb_addr);
        log::info!("====== kernel memory layout end ======");

        println!("[PROBE_DEV_TREE] try to init");
        osdriver::probe_device_tree();
        println!("[PROBE_DEV_TREE] INIT SUCCESS");

        println!("device init");

        log::info!("hart {}: initialized driver", hart_id);

        osfs::init();
        log::info!("hart {}: initialized FS success", hart_id);
        println!("[FILE_SYSTEM] INIT SUCCESS");

        // boot::start_harts(hart_id);
        loader::init();
        syscall::init_key();

        executor::init(hart_id);
        task::init();
        println!("[USER_APP] INIT SUCCESS");
        println!("[HART {}] INIT SUCCESS", hart_id);
        println!("{}", OWNSOME_BANNER);
    } else {
        executor::init(hart_id);
        log::info!("hart {}: enabling page table", hart_id);
        // SAFETY: Only after the first hart has initialized the heap allocator and page table,
        // do the other harts enable the kernel page table.
        unsafe {
            vm::switch_to_kernel_page_table();
        }
        println!("[HART {}] INIT SUCCESS", hart_id);
        panic!("multi-core unsupported");
    }

    #[cfg(target_arch = "loongarch64")]
    trap::trap_handler::tlb_init();

    // println!("init trap");
    arch::trap::init();
    // println!("set_kernel_trap_entry");
    trap::trap_env::set_kernel_trap_entry();
    // println!("init_timer");
    arch::time::init_timer();

    vfs::path::test_split_parent_and_name();

    // hart::init(hart_id);
    log::info!("hart {}: running", hart_id);
    osfuture::block_on(async { test_serial_output().await });
    println!("Begin to run shell..");
    loop {
        executor::task_run_always_alone(hart_id);
    }
}

use arch::hart::hart_start;
use config::device::MAX_HARTS;
use config::mm::HART_START_ADDR;
use driver::println;

/// start mutil cores
#[allow(unused)]
pub fn start_harts(hart_id: usize) {
    for i in 0..MAX_HARTS {
        if i == hart_id {
            continue;
        }
        hart_start(i, HART_START_ADDR);
    }
}

/// Clear BSS segment at start up.
pub fn clear_bss() {
    unsafe extern "C" {
        fn _sbss();
        fn _kbss();
        fn _ebss();
    }
    unsafe {
        let start = _kbss as usize as *mut u64;
        let end = _ebss as usize as *mut u64;

        println!("s-kbss: {:#x} -  {:#x}", _sbss as usize, _kbss as usize);
        println!("k-ebss: {:#x} -  {:#x}", _kbss as usize, _ebss as usize);

        let len = end.offset_from(start) as usize;
        core::slice::from_raw_parts_mut(start, len).fill(0);

        // Handle any remaining bytes if the length is not a multiple of u64
        let start_byte = start as *mut u8;
        let len_bytes = _ebss as usize - _kbss as usize;
        if len_bytes % 8 != 0 {
            let offset = len * 8;
            core::slice::from_raw_parts_mut(start_byte.add(offset), len_bytes - offset).fill(0);
        }
    }
}

use std::{env, fs, path::PathBuf};

use config::mm::{KERNEL_RAM_OFFSET, KERNEL_START_PHYS, RAM_SIZE};

fn main() {
    #![allow(non_snake_case)]

    let manifest_dir = env::var("CARGO_MANIFEST_DIR").unwrap();
    let out_dir = env::var("OUT_DIR").unwrap();
    let target_arch = env::var("CARGO_CFG_TARGET_ARCH").unwrap();
    let target_triple = env::var("TARGET").unwrap();
    let compile_profile = env::var("PROFILE").unwrap();

    let ram_size = RAM_SIZE - KERNEL_RAM_OFFSET;
    let target_arch_acronym = match target_arch.as_str() {
        "riscv64" => "rv",
        "loongarch64" => "la",
        _ => panic!("Unsupported target architecture"),
    };

    // Note: Remember to copy the constants from `lib/config/src/mm.rs` to here.
    // This is a workaround for the fact that the build script is compiled for the host
    // architecture, not the target architecture of the kernel.
    let VIRT_START: usize = match target_arch.as_str() {
        "riscv64" => 0xffff_ffc0_8000_0000,
        "loongarch64" => 0x9000_0000_8000_0000,
        _ => panic!("Unsupported target architecture"),
    };
    let KERNEL_START: usize = VIRT_START + KERNEL_RAM_OFFSET;

    // Generate the linker script.
    let link_script = fs::read_to_string(PathBuf::from(manifest_dir.clone()).join("linker.ld"))
        .unwrap()
        .replace("%RAM_START%", &KERNEL_START_PHYS.to_string())
        .replace("%VIRT_START%", &KERNEL_START.to_string())
        .replace("%RAM_SIZE%", &ram_size.to_string());
    let linker_script_dest = PathBuf::from(out_dir).join("linker.ld");
    fs::write(&linker_script_dest, link_script).unwrap();
    println!("cargo:rustc-link-arg=-T{}", linker_script_dest.display());

    let linkapp =
        fs::read_to_string(PathBuf::from(manifest_dir.clone()).join("src/linkapp.asm.tmpl"))
            .unwrap()
            .replace("<cargo-target>", &target_triple)
            .replace("<cargo-profile>", &compile_profile)
            .replace("<cargo-target-acronym>", target_arch_acronym);
    let linkapp_dest = PathBuf::from(manifest_dir).join("src/linkapp.asm");
    fs::write(&linkapp_dest, linkapp).unwrap();
}

